import xml.etree.ElementTree as ET
import os

pkg_xml = None
for root, dirs, files in os.walk('/evidence/FOR_400/'):
    for f in files:
        if f == 'packages.xml':
            pkg_xml = os.path.join(root, f)
            break
    if pkg_xml:
