import re, os

# Find the class with the byte array
for root, dirs, files in os.walk('/tmp/jadx_out/'):
    for f in files:
        if f.endswith('.java'):
            path = os.path.join(root, f)
            with open(path, 'r', errors='replace') as fh:
                content = fh.read()
            if 'Socket' in content and 'byte' in content:
                # Find byte array initializations
                arrays = re.findall(r'new byte\[\]\s*\{([^}]+)\}', content)
                for arr in arrays:
                    # Parse byte values
                    try:
                        vals = [int(x.strip().replace('(byte)', '').strip()) & 0xFF for x in arr.split(',')]
                        # Try as ASCII/UTF-8
                        decoded = ''.join(chr(v) for v in vals if 32 <= v < 127)
                        if '.' in decoded and all(c.isdigit() or c == '.' for c in decoded):
                            print(f'DECODED IP: {decoded} from {os.path.basename(path)}')
                        elif decoded:
                            print(f'DECODED STRING: {decoded} from {os.path.basename(path)}')
                        # Also try as raw IP octets
                        if len(vals) == 4:
                            ip = '.'.join(str(v) for v in vals)
                            print(f'RAW IP OCTETS: {ip} from {os.path.basename(path)}')
                    except (ValueError, IndexError):
                        pass

