import subprocess, re, base64
result = subprocess.run(['strings', '-n', '20', '/evidence/FOR_800/memory.lime'], capture_output=True, text=True, timeout=300)
lines = result.stdout.splitlines()
for i, line in enumerate(lines):
    if any(kw in line.lower() for kw in ['ignore', 'prompt', 'inject', 'system:', 'execute', 'eval(', 'exec(', '__import__']):
        # Print context around the match
        context = lines[max(0,i-3):i+5]
        for c in context:
            print(c)
        print('---')
    # Also check for base64 blobs
    b64 = re.findall(r'[A-Za-z0-9+/]{40,}={0,2}', line)
    for b in b64:
        try:
            decoded = base64.b64decode(b).decode('utf-8', errors='replace')
            if any(kw in decoded.lower() for kw in ['import', 'exec', 'eval', 'os.', 'system', 'subprocess', 'shell']):
                print(f'DECODED PAYLOAD: {decoded}')
        except Exception:
            pass

import subprocess, base64, re
result = subprocess.run(['tshark', '-r', '/evidence/FOR_800/traffic.pcap', '-Y', 'dns.qry.name', '-T', 'fields', '-e', 'dns.qry.name'], capture_output=True, text=True, timeout=120)
subdomains = []
for line in result.stdout.strip().splitlines():
    # DNS tunnel data is usually in the subdomain part
    parts = line.strip().split('.')
    if len(parts) > 2:
        subdomains.append(parts[0])

# Try base32 decode (common for dnscat2)
data = ''.join(subdomains)
try:
    decoded = base64.b32decode(data + '=' * (8 - len(data) % 8)).decode('utf-8', errors='replace')
    print(f'BASE32 decoded: {decoded}')
except Exception as e:
    print(f'Base32 failed: {e}')
    # Try base64
    try:
        decoded = base64.b64decode(data).decode('utf-8', errors='replace')
        print(f'BASE64 decoded: {decoded}')
    except Exception:
        # Try hex
        try:
            decoded = bytes.fromhex(data).decode('utf-8', errors='replace')
            print(f'HEX decoded: {decoded}')
        except Exception:
            print(f'Raw subdomains: {data[:500]}')
